$(document).ready(function () {

  // Expand/Collapse logic
  $(".expand").click(function () {
    $(".extra, .less").show();
    $(".expand").hide();
    $(".grid-container").css("max-height", "max-content");
  });

  $(".less").click(function () {
    $(".extra, .less").hide();
    $(".expand").show();
    $(".grid-container").css("max-height", "160px");
  });

  $(document).click(function(event) {
    // Check if the click is outside of the grid-container
    if (!$(event.target).closest('.grid-container').length) {
        if ($(".less").is(":visible")) {
            // Perform the same actions as the .less button click
            $(".extra, .less").hide();
            $(".expand").show();
            $(".grid-container").css("max-height", "160px");
        }
    }
});

  // Localities popup logic
  $("#moreBtn").click(function () {
    $(".localities_popup").show();
  });

  $("#closeBtn").click(function () {
    $(".localities_popup").hide();
  });

  $(document).click(function (e) {
    if (!$(e.target).closest("#moreBtn, .localities_popup").length) {
      $(".localities_popup").hide();
    }
  });
  $("#moreSportBtn").click(function () {
    $(".sports_popup").show();
  });

  $("#closeSportBtn").click(function () {
    $(".sports_popup").hide();
  });

  $(document).click(function (e) {
    if (!$(e.target).closest("#moreSportBtn, .sports_popup").length) {
      $(".sports_popup").hide();
    }
  });

  //========== location js========================//

  function getLocation() {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(showPosition, showError);
    } else {
      console.error("Geolocation is not supported by this browser.");
    }
  }

  // Function to display the current position
  function showPosition(position) {
    var latitude = position.coords.latitude;
    var longitude = position.coords.longitude;
    window.open(
      `https://www.bookmyplayer.com/sdid/redirect/${latitude}-${longitude}`,
      "_blank"
    );
  }

  // Function to handle errors in geolocation
  function showError(error) {
    switch (error.code) {
      case error.PERMISSION_DENIED:
        console.log("User denied the request for Geolocation.");
        break;
      case error.POSITION_UNAVAILABLE:
        console.log("Location information is unavailable.");
        break;
      case error.TIMEOUT:
        console.log("The request to get user location timed out.");
        break;
      case error.UNKNOWN_ERROR:
        console.log("An unknown error occurred.");
        break;
    }
  }

  // Attach click event handler to the element with ID "lat_lng_finder"
  $("#lat_lng_finder").click(function () {
    getLocation();
  });

  //========== location js ends========================//

  //============ sorting top rated for mobile js=================//
  $("#top_rated").click(function () {
    // Assuming sortAcademiesNew is called to sort in descending order by default
    sortAcademiesNew(false); // Pass false to sort from highest to lowest
    $(".rate_sort").addClass('active_filter');
  });

  function sortAcademiesNew(isAscending = false) {
    // Default isDescending to false
    var $cards = $(".list-menu")
      .toArray()
      .sort(function (a, b) {
        // Extracting the numeric rating value or defaulting to 0
        var matchA = $(a)
          .find(".rating_value")
          .text()
          .match(/(\d+(\.\d+)?)/);
        var ratingA = matchA ? parseFloat(matchA[0]) : 0;

        var matchB = $(b)
          .find(".rating_value")
          .text()
          .match(/(\d+(\.\d+)?)/);
        var ratingB = matchB ? parseFloat(matchB[0]) : 0;

        // Adjusting the comparison for numerical sorting
        return isAscending ? ratingA - ratingB : ratingB - ratingA;
      });

    // Re-append sorted cards to the container
    $(".new_list").empty().append($cards);
  }

  //============ sorting top rated for mobile js ends=================//

  //============ sorting js ends=================//

  //=========== sports on mobile display ==============//
  $("#openPopup").click(function () {
    $("#sports_popup_content, #popup_overlay").show();
    $(".sport_sort").addClass('active_filter');
  });

  $(".popup_close_icon, #popup_overlay").click(function () {
    $("#sports_popup_content, #popup_overlay").hide();
  });

  // Prevent closing the popup when clicking inside the popup content
  $("#sports_popup_content").click(function (event) {
    event.stopPropagation();
  });
  // ============sports on mobile display ends============//

  //================on hover locality name js==========//

  $('.grid-item').hover(
    function() {
      // Mouse enters the .grid-item
      $(this).find('.locality-name').show();
    }, function() {
      // Mouse leaves the .grid-item
      $(this).find('.locality-name').hide();
    }
  );
  //================on hover locality name js ends==========//

  // ============ Load more start ============== //
  // Initialize offset to the number of already loaded academies
  // var offset = $('.list-menu').length;

  // $('#loadMoreButton').click(function () {
  //     $.ajax({
  //         url: window.location.href,
  //         method: 'GET',
  //         data: { offset: offset },
  //         success: function (response) {
  //             var newAcademies = $(response).find('.list-menu');
  //             if (newAcademies.length > 0) {
  //                 $('.list-menu:last').after(newAcademies);
  //                 offset += newAcademies.length; // Update offset with the number of newly loaded academies
  //             } else {
  //                 $('#loadMoreButton').hide();
  //             }
  //         },
  //         error: function (xhr, status, error) {
  //             console.error('Error loading academies:', error);
  //         }
  //     });
  // });

  // ============ Load more end ============== //

  //=========locality search===========//
  
  //===========locality search js==========//
  var originalWrapperHTML = $('#localities_wrapper_desk').html(); // Store the original HTML of the wrapper
  

  var allLocalities = JSON.parse($('#localitiesData').attr('data-localities'));
  allLocalities = allLocalities.map(function(locality) {
      return {name: locality.locality_name, url: locality.url};
  });
  
function filterLocalities() {
    var filter = $('#searchLocality').val().toUpperCase();
    var $localitiesWrapper = $('#localities_wrapper_desk');
    var $initialLocalitiesDiv = $('#initialLocalities');
    var $moreBtn = $('#moreBtn');

    // Clear current content and hide the "More" button based on the search input
    $initialLocalitiesDiv.html('');

    if(filter){
      $moreBtn.hide();
    }else{
      $localitiesWrapper.html(originalWrapperHTML);
      $moreBtn.show();
      attachMoreButtonListener();
    }


    // Filter allLocalities based on search query
    var filteredLocalities = allLocalities.filter(function(locality) {
        return locality.name.toUpperCase().indexOf(filter) > -1;
    });

    // Append filtered localities or show 'no localities found'
    if (filteredLocalities.length) {
        filteredLocalities.forEach(function(locality) {
            var $locality = $('<a target="_blank" href="' + locality.url + '" class="sector_tag_desk"><button class="sort_btn"><span>' + locality.name + '</span></button></a>');
            $initialLocalitiesDiv.append($locality);
        });
    } else {
        $initialLocalitiesDiv.html('<p>No localities found.</p>');
    }
}

  function attachMoreButtonListener() {
    $("#moreBtn").click(function () {
      $(".localities_popup").show();
    });
  
    $("#closeBtn").click(function () {
      $(".localities_popup").hide();
    });
  }

  // Initial setup
  attachMoreButtonListener();
  $('#searchLocality').on('keyup', filterLocalities);

  //===========locality search js ends==========//
  //=========locality search ends===========//

});
